{
  "name": "AI Bilingual Exam Prep",
  "description": "A professional bilingual exam simulator that uses Gemini AI to analyze question images (PNG) and provide instant feedback and explanations in Portuguese and English."
}

export interface QuestionData {
  id: string;
  image: string; // base64 or URL
  extractedText: {
    question: string;
    options: { [key: string]: string };
  };
  correctAnswer: string;
  explanationPT: string;
  explanationEN: string;
}

export interface ExamSession {
  questions: QuestionData[];
  currentIndex: number;
  score: number;
  answers: { [key: string]: string };
  isFinished: boolean;
}

export enum AppStatus {
  SETUP = 'SETUP',
  LOADING = 'LOADING',
  EXAM = 'EXAM',
  RESULT = 'RESULT'
}

import { GoogleGenAI, Type } from "@google/genai";

const MODEL_NAME = 'gemini-3-flash-preview';

export async function analyzeQuestionImage(base64Image: string): Promise<any> {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

  const prompt = `
    Analyze this exam question image. 
    1. Extract the question text.
    2. Extract the multiple choice options (A, B, C, D, etc.).
    3. Identify the correct answer (A, B, C, D, etc.).
    4. Provide a detailed explanation of why that answer is correct and why the others are wrong in Portuguese.
    5. Provide the same detailed explanation in English.

    Output MUST be in the specified JSON format.
  `;

  const response = await ai.models.generateContent({
    model: MODEL_NAME,
    contents: {
      parts: [
        {
          inlineData: {
            mimeType: 'image/png',
            data: base64Image.split(',')[1] || base64Image,
          },
        },
        { text: prompt },
      ],
    },
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          question: { type: Type.STRING },
          options: {
            type: Type.OBJECT,
            properties: {
              A: { type: Type.STRING },
              B: { type: Type.STRING },
              C: { type: Type.STRING },
              D: { type: Type.STRING },
              E: { type: Type.STRING },
            }
          },
          correctAnswer: { type: Type.STRING, description: "Single letter representing the correct option" },
          explanationPT: { type: Type.STRING },
          explanationEN: { type: Type.STRING },
        },
        required: ["question", "options", "correctAnswer", "explanationPT", "explanationEN"]
      }
    }
  });

  try {
    return JSON.parse(response.text || '{}');
  } catch (e) {
    console.error("Failed to parse Gemini response", e);
    throw new Error("Could not analyze the question image correctly.");
  }
}

import React, { useState } from 'react';
import { QuestionData } from '../types';

interface ExamViewProps {
  question: QuestionData;
  onAnswer: (selected: string) => void;
  onNext: () => void;
  currentIndex: number;
  totalQuestions: number;
}

const ExamView: React.FC<ExamViewProps> = ({ 
  question, 
  onAnswer, 
  onNext, 
  currentIndex, 
  totalQuestions 
}) => {
  const [selectedOption, setSelectedOption] = useState<string | null>(null);
  const [showExplanation, setShowExplanation] = useState(false);
  const [isCorrect, setIsCorrect] = useState<boolean | null>(null);

  const handleOptionSelect = (option: string) => {
    if (showExplanation) return;
    setSelectedOption(option);
    const correct = option === question.correctAnswer;
    setIsCorrect(correct);
    setShowExplanation(true);
    onAnswer(option);
  };

  const handleNext = () => {
    setSelectedOption(null);
    setShowExplanation(false);
    setIsCorrect(null);
    onNext();
  };

  return (
    <div className="max-w-6xl mx-auto p-4 md:p-8">
      <div className="mb-6 flex items-center justify-between">
        <div className="flex flex-col">
          <span className="text-sm font-semibold text-slate-500 uppercase tracking-wider">Questão {currentIndex + 1} de {totalQuestions}</span>
          <div className="w-64 h-2 bg-slate-200 rounded-full mt-2 overflow-hidden">
            <div 
              className="h-full bg-blue-600 transition-all duration-500" 
              style={{ width: `${((currentIndex + 1) / totalQuestions) * 100}%` }}
            ></div>
          </div>
        </div>
        <div className="text-right">
          <span className="bg-slate-100 text-slate-700 px-3 py-1 rounded-md text-sm font-medium border border-slate-200">
            Simulado Oficial (Draft)
          </span>
        </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
        {/* Left: Original Image & Extracted Context */}
        <div className="space-y-6">
          <div className="bg-white p-4 rounded-xl border border-slate-200 shadow-sm">
            <h3 className="text-xs font-bold text-slate-400 mb-3 uppercase tracking-widest">Imagem Original / Original Image</h3>
            <img 
              src={question.image} 
              alt="Question" 
              className="w-full h-auto rounded-lg border border-slate-100"
            />
          </div>

          <div className="bg-slate-50 p-6 rounded-xl border border-slate-200">
            <h2 className="text-xl font-semibold text-slate-800 leading-relaxed">
              {question.extractedText.question}
            </h2>
          </div>
        </div>

        {/* Right: Interaction and Feedback */}
        <div className="space-y-6">
          <div className="bg-white rounded-xl border border-slate-200 shadow-sm overflow-hidden">
            <div className="p-6">
              <h3 className="text-sm font-bold text-slate-500 mb-4 uppercase tracking-wider">Selecione a resposta / Select your answer</h3>
              <div className="space-y-3">
                {Object.entries(question.extractedText.options).map(([key, text]) => {
                  if (!text) return null;
                  const isSelected = selectedOption === key;
                  const isCorrectAnswer = key === question.correctAnswer;

                  let buttonClass = "w-full text-left p-4 rounded-lg border transition-all duration-200 flex items-start gap-3 ";

                  if (showExplanation) {
                    if (isCorrectAnswer) {
                      buttonClass += "bg-emerald-50 border-emerald-500 text-emerald-900 shadow-sm";
                    } else if (isSelected && !isCorrectAnswer) {
                      buttonClass += "bg-rose-50 border-rose-500 text-rose-900";
                    } else {
                      buttonClass += "bg-slate-50 border-slate-200 text-slate-400 opacity-60";
                    }
                  } else {
                    buttonClass += isSelected 
                      ? "bg-blue-50 border-blue-500 text-blue-700 shadow-md ring-2 ring-blue-100" 
                      : "bg-white border-slate-200 text-slate-700 hover:border-blue-300 hover:bg-slate-50";
                  }

                  return (
                    <button
                      key={key}
                      disabled={showExplanation}
                      onClick={() => handleOptionSelect(key)}
                      className={buttonClass}
                    >
                      <span className={`flex-shrink-0 w-8 h-8 rounded-full flex items-center justify-center font-bold text-sm ${
                        showExplanation && isCorrectAnswer ? 'bg-emerald-500 text-white' : 
                        showExplanation && isSelected && !isCorrectAnswer ? 'bg-rose-500 text-white' :
                        isSelected ? 'bg-blue-500 text-white' : 'bg-slate-100 text-slate-500'
                      }`}>
                        {key}
                      </span>
                      <span className="flex-1 text-base">{text}</span>
                    </button>
                  );
                })}
              </div>
            </div>

            {showExplanation && (
              <div className={`p-6 border-t ${isCorrect ? 'bg-emerald-50 border-emerald-100' : 'bg-rose-50 border-rose-100'}`}>
                <div className="flex items-center gap-2 mb-4">
                  {isCorrect ? (
                    <span className="text-emerald-700 font-bold flex items-center gap-1">
                      <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" viewBox="0 0 20 20" fill="currentColor">
                        <path fillRule="evenodd" d="M10 18a8 8 0 100-16 8 8 0 000 16zm3.707-9.293a1 1 0 00-1.414-1.414L9 10.586 7.707 9.293a1 1 0 00-1.414 1.414l2 2a1 1 0 001.414 0l4-4z" clipRule="evenodd" />
                      </svg>
                      Correto! / Correct!
                    </span>
                  ) : (
                    <span className="text-rose-700 font-bold flex items-center gap-1">
                      <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" viewBox="0 0 20 20" fill="currentColor">
                        <path fillRule="evenodd" d="M10 18a8 8 0 100-16 8 8 0 000 16zM8.707 7.293a1 1 0 00-1.414 1.414L8.586 10l-1.293 1.293a1 1 0 101.414 1.414L10 11.414l1.293 1.293a1 1 0 001.414-1.414L11.414 10l1.293-1.293a1 1 0 00-1.414-1.414L10 8.586 8.707 7.293z" clipRule="evenodd" />
                      </svg>
                      Incorreto! / Incorrect!
                    </span>
                  )}
                </div>

                <div className="space-y-6">
                  <div>
                    <h4 className="text-xs font-bold text-slate-500 uppercase mb-2">Explicação (PT-BR)</h4>
                    <p className="text-slate-800 text-sm leading-relaxed">{question.explanationPT}</p>
                  </div>
                  <div className="border-t border-slate-200 pt-4">
                    <h4 className="text-xs font-bold text-slate-500 uppercase mb-2">Explanation (EN-US)</h4>
                    <p className="text-slate-800 text-sm leading-relaxed">{question.explanationEN}</p>
                  </div>
                </div>

                <button
                  onClick={handleNext}
                  className="mt-8 w-full bg-slate-800 hover:bg-slate-900 text-white font-bold py-3 px-6 rounded-lg shadow-lg transition-all transform hover:-translate-y-0.5 active:translate-y-0"
                >
                  {currentIndex + 1 === totalQuestions ? 'Finalizar Simulado' : 'Próxima Questão / Next Question'}
                </button>
              </div>
            )}
          </div>
        </div>
      </div>
    </div>
  );
};

export default ExamView;

import React, { useState, useCallback } from 'react';
import { AppStatus, QuestionData, ExamSession } from './types';
import { analyzeQuestionImage } from './services/geminiService';
import ExamView from './components/ExamView';

const App: React.FC = () => {
  const [status, setStatus] = useState<AppStatus>(AppStatus.SETUP);
  const [session, setSession] = useState<ExamSession | null>(null);
  const [loadingProgress, setLoadingProgress] = useState(0);
  const [error, setError] = useState<string | null>(null);

  const handleFileUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const files = e.target.files;
    if (!files || files.length === 0) return;

    setStatus(AppStatus.LOADING);
    setLoadingProgress(0);
    setError(null);

    const questions: QuestionData[] = [];
    const totalFiles = files.length;

    try {
      for (let i = 0; i < totalFiles; i++) {
        const file = files[i];
        if (!file.type.startsWith('image/')) continue;

        // Convert to base64
        const reader = new FileReader();
        const base64Promise = new Promise<string>((resolve) => {
          reader.onload = () => resolve(reader.result as string);
          reader.readAsDataURL(file);
        });
        const base64 = await base64Promise;

        // Analyze with Gemini
        try {
          const result = await analyzeQuestionImage(base64);
          questions.push({
            id: `q-${i}`,
            image: base64,
            extractedText: {
              question: result.question,
              options: result.options
            },
            correctAnswer: result.correctAnswer,
            explanationPT: result.explanationPT,
            explanationEN: result.explanationEN
          });
        } catch (err) {
          console.warn(`Error analyzing question ${i}:`, err);
          // We can choose to skip or stop. Let's skip one and continue.
        }

        setLoadingProgress(Math.round(((i + 1) / totalFiles) * 100));
      }

      if (questions.length === 0) {
        throw new Error("Não foi possível processar nenhuma imagem de questão.");
      }

      setSession({
        questions,
        currentIndex: 0,
        score: 0,
        answers: {},
        isFinished: false
      });
      setStatus(AppStatus.EXAM);
    } catch (err: any) {
      setError(err.message || "Erro inesperado.");
      setStatus(AppStatus.SETUP);
    }
  };

  const handleAnswer = (selected: string) => {
    if (!session) return;
    const isCorrect = selected === session.questions[session.currentIndex].correctAnswer;
    setSession(prev => prev ? ({
      ...prev,
      score: isCorrect ? prev.score + 1 : prev.score,
      answers: { ...prev.answers, [prev.questions[prev.currentIndex].id]: selected }
    }) : null);
  };

  const handleNext = () => {
    if (!session) return;
    if (session.currentIndex + 1 >= session.questions.length) {
      setStatus(AppStatus.RESULT);
    } else {
      setSession(prev => prev ? ({ ...prev, currentIndex: prev.currentIndex + 1 }) : null);
    }
  };

  const reset = () => {
    setStatus(AppStatus.SETUP);
    setSession(null);
    setLoadingProgress(0);
    setError(null);
  };

  return (
    <div className="min-h-screen bg-slate-50 text-slate-900">
      {/* Header */}
      <header className="bg-white border-b border-slate-200 sticky top-0 z-10 shadow-sm">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-4 flex justify-between items-center">
          <div className="flex items-center gap-2">
            <div className="w-10 h-10 bg-blue-600 rounded-lg flex items-center justify-center shadow-lg">
              <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6 text-white" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 12l2 2 4-4m6 2a9 9 0 11-18 0 9 9 0 0118 0z" />
              </svg>
            </div>
            <div>
              <h1 className="text-xl font-bold text-slate-800 tracking-tight">ExamPrep <span className="text-blue-600">AI</span></h1>
              <p className="text-xs font-medium text-slate-500 uppercase tracking-widest">Bilingual Simulator</p>
            </div>
          </div>
          {status !== AppStatus.SETUP && (
            <button 
              onClick={reset}
              className="text-sm font-semibold text-rose-600 hover:text-rose-700 transition-colors"
            >
              Encerrar / Exit
            </button>
          )}
        </div>
      </header>

      <main>
        {status === AppStatus.SETUP && (
          <div className="max-w-3xl mx-auto py-12 px-4 text-center">
            <h2 className="text-4xl font-extrabold text-slate-900 mb-6">Transforme suas imagens em um simulado oficial</h2>
            <p className="text-lg text-slate-600 mb-10 max-w-2xl mx-auto">
              Baixe suas questões do Google Drive (formato PNG) e selecione-as abaixo. 
              Nossa IA irá criar um teste bilingue com correção em tempo real.
            </p>

            <div className="bg-white p-10 rounded-3xl border-2 border-dashed border-slate-300 shadow-sm hover:border-blue-400 transition-colors group relative">
              <div className="flex flex-col items-center">
                <div className="w-20 h-20 bg-blue-50 text-blue-500 rounded-2xl flex items-center justify-center mb-6 group-hover:scale-110 transition-transform duration-300">
                  <svg xmlns="http://www.w3.org/2000/svg" className="h-10 w-10" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 16l4.586-4.586a2 2 0 012.828 0L16 16m-2-2l1.586-1.586a2 2 0 012.828 0L20 14m-6-6h.01M6 20h12a2 2 0 002-2V6a2 2 0 00-2-2H6a2 2 0 00-2 2v12a2 2 0 002 2z" />
                  </svg>
                </div>
                <label className="cursor-pointer">
                  <span className="bg-blue-600 hover:bg-blue-700 text-white font-bold py-3 px-8 rounded-full shadow-lg transition-all inline-block">
                    Selecionar Imagens da Pasta
                  </span>
                  <input 
                    type="file" 
                    multiple 
                    accept="image/png,image/jpeg" 
                    onChange={handleFileUpload} 
                    className="hidden" 
                  />
                </label>
                <p className="mt-4 text-sm text-slate-500 font-medium">Suporta PNG, JPG e JPEG</p>
              </div>
            </div>

            {error && (
              <div className="mt-6 p-4 bg-rose-50 border border-rose-200 text-rose-700 rounded-xl text-sm font-medium">
                {error}
              </div>
            )}

            <div className="mt-16 grid grid-cols-1 md:grid-cols-3 gap-8 text-left">
              <div className="p-6 bg-white rounded-2xl shadow-sm border border-slate-100">
                <div className="text-blue-600 font-bold mb-2">01. Análise IA</div>
                <p className="text-sm text-slate-600">Extração inteligente de texto e imagens utilizando Gemini 3 Flash.</p>
              </div>
              <div className="p-6 bg-white rounded-2xl shadow-sm border border-slate-100">
                <div className="text-blue-600 font-bold mb-2">02. Bilingue</div>
                <p className="text-sm text-slate-600">Explicações detalhadas em Português e Inglês para cada resposta.</p>
              </div>
              <div className="p-6 bg-white rounded-2xl shadow-sm border border-slate-100">
                <div className="text-blue-600 font-bold mb-2">03. Formato Oficial</div>
                <p className="text-sm text-slate-600">Interface limpa e profissional simulando centros de exame reais.</p>
              </div>
            </div>
          </div>
        )}

        {status === AppStatus.LOADING && (
          <div className="max-w-md mx-auto py-32 px-4 text-center">
            <div className="relative w-32 h-32 mx-auto mb-8">
              <div className="absolute inset-0 border-4 border-blue-100 rounded-full"></div>
              <div 
                className="absolute inset-0 border-4 border-blue-600 rounded-full border-t-transparent animate-spin"
                style={{ animationDuration: '2s' }}
              ></div>
              <div className="absolute inset-0 flex items-center justify-center font-bold text-xl text-blue-600">
                {loadingProgress}%
              </div>
            </div>
            <h3 className="text-2xl font-bold mb-2">Processando Questões...</h3>
            <p className="text-slate-500">Nossa IA está lendo suas imagens e preparando as explicações bilingues.</p>
          </div>
        )}

        {status === AppStatus.EXAM && session && (
          <ExamView 
            question={session.questions[session.currentIndex]}
            currentIndex={session.currentIndex}
            totalQuestions={session.questions.length}
            onAnswer={handleAnswer}
            onNext={handleNext}
          />
        )}

        {status === AppStatus.RESULT && session && (
          <div className="max-w-2xl mx-auto py-16 px-4">
            <div className="bg-white rounded-3xl p-10 shadow-xl border border-slate-100 text-center">
              <div className="w-24 h-24 bg-emerald-50 text-emerald-500 rounded-full flex items-center justify-center mx-auto mb-6 shadow-inner">
                <svg xmlns="http://www.w3.org/2000/svg" className="h-12 w-12" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M5 13l4 4L19 7" />
                </svg>
              </div>
              <h2 className="text-3xl font-extrabold mb-2">Simulado Concluído!</h2>
              <p className="text-slate-500 mb-10">Confira seu desempenho abaixo.</p>

              <div className="grid grid-cols-2 gap-4 mb-10">
                <div className="p-6 bg-slate-50 rounded-2xl border border-slate-100">
                  <div className="text-4xl font-black text-slate-900">{session.score}</div>
                  <div className="text-xs font-bold text-slate-400 uppercase tracking-widest mt-1">Acertos</div>
                </div>
                <div className="p-6 bg-slate-50 rounded-2xl border border-slate-100">
                  <div className="text-4xl font-black text-slate-900">{Math.round((session.score / session.questions.length) * 100)}%</div>
                  <div className="text-xs font-bold text-slate-400 uppercase tracking-widest mt-1">Precisão</div>
                </div>
              </div>

              <div className="space-y-4">
                <button 
                  onClick={reset}
                  className="w-full bg-blue-600 hover:bg-blue-700 text-white font-bold py-4 rounded-xl shadow-lg transition-all transform hover:-translate-y-1"
                >
                  Novo Simulado / New Exam
                </button>
              </div>
            </div>
          </div>
        )}
      </main>

      <footer className="py-12 border-t border-slate-200 mt-20">
        <div className="max-w-7xl mx-auto px-4 text-center">
          <p className="text-sm text-slate-400">© 2024 ExamPrep AI - Powered by Gemini Flash 3.0</p>
        </div>
      </footer>
    </div>
  );
};

export default App;

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
