import React, { useState } from 'react';
import { AppStatus, QuestionData, ExamSession } from './types';
import { analyzeQuestionImage } from './services/geminiService';
import ExamView from './components/ExamView';

declare module 'react' {
  interface InputHTMLAttributes<T> extends HTMLAttributes<T> {
    webkitdirectory?: string;
    directory?: string;
  }
}

const App: React.FC = () => {
  const [status, setStatus] = useState<AppStatus>(AppStatus.SETUP);
  const [session, setSession] = useState<ExamSession | null>(null);
  const [loadingProgress, setLoadingProgress] = useState(0);
  const [currentFileName, setCurrentFileName] = useState("");
  const [error, setError] = useState<string | null>(null);

  const handleFileUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const files = e.target.files;
    if (!files || files.length === 0) return;

    setStatus(AppStatus.LOADING);
    setLoadingProgress(0);
    setError(null);

    const questions: QuestionData[] = [];
    // Filtrar apenas imagens válidas de todos os arquivos encontrados (incluindo subpastas)
    const validImageFiles = Array.from(files).filter(file => 
      file.type.startsWith('image/png') || file.type.startsWith('image/jpeg')
    );

    const totalFiles = validImageFiles.length;

    if (totalFiles === 0) {
      setError("Nenhuma imagem PNG ou JPG encontrada na pasta selecionada.");
      setStatus(AppStatus.SETUP);
      return;
    }

    try {
      for (let i = 0; i < totalFiles; i++) {
        const file = validImageFiles[i];
        setCurrentFileName(file.name);

        // Convert to base64
        const reader = new FileReader();
        const base64Promise = new Promise<string>((resolve) => {
          reader.onload = () => resolve(reader.result as string);
          reader.readAsDataURL(file);
        });
        const base64 = await base64Promise;

        // Analyze with Gemini
        try {
          const result = await analyzeQuestionImage(base64);
          questions.push({
            id: `q-${i}-${Date.now()}`,
            image: base64,
            extractedText: {
              question: result.question,
              options: result.options
            },
            correctAnswer: result.correctAnswer,
            explanationPT: result.explanationPT,
            explanationEN: result.explanationEN
          });
        } catch (err) {
          console.warn(`Erro ao analisar a imagem ${file.name}:`, err);
          // Continua para a próxima imagem mesmo se uma falhar
        }

        setLoadingProgress(Math.round(((i + 1) / totalFiles) * 100));
      }

      if (questions.length === 0) {
        throw new Error("Não foi possível extrair dados de nenhuma das imagens processadas.");
      }

      setSession({
        questions,
        currentIndex: 0,
        score: 0,
        answers: {},
        isFinished: false
      });
      setStatus(AppStatus.EXAM);
    } catch (err: any) {
      setError(err.message || "Erro inesperado ao processar a pasta.");
      setStatus(AppStatus.SETUP);
    }
  };

  const handleAnswer = (selected: string) => {
    if (!session) return;
    const isCorrect = selected === session.questions[session.currentIndex].correctAnswer;
    setSession(prev => prev ? ({
      ...prev,
      score: isCorrect ? prev.score + 1 : prev.score,
      answers: { ...prev.answers, [prev.questions[prev.currentIndex].id]: selected }
    }) : null);
  };

  const handleNext = () => {
    if (!session) return;
    if (session.currentIndex + 1 >= session.questions.length) {
      setStatus(AppStatus.RESULT);
    } else {
      setSession(prev => prev ? ({ ...prev, currentIndex: prev.currentIndex + 1 }) : null);
    }
  };

  const reset = () => {
