    setError(null);

    const questions: QuestionData[] = [];

    // Cast Array.from result to File[] to fix 'unknown' type errors
    const fileArray = Array.from(files) as File[];

    // Filter valid image files
    const validImageFiles = fileArray.filter(file => 
      file.type.startsWith('image/png') || file.type.startsWith('image/jpeg')
    );

    const totalFiles = validImageFiles.length;

    if (totalFiles === 0) {
      setError("Nenhuma imagem PNG ou JPG encontrada na pasta selecionada.");
      setStatus(AppStatus.SETUP);
      return;
    }

    try {
      for (let i = 0; i < totalFiles; i++) {
        const file = validImageFiles[i];
