                >
                  Histórico ({history.length})
                </button>
              </div>
            </div>
          </div>
        )}

        {status === AppStatus.HISTORY && (
          <div className="py-12 max-w-4xl mx-auto">
            <div className="flex justify-between items-end mb-10">
              <div>
