import { GoogleGenAI, Type } from "@google/genai";

const MODEL_NAME = 'gemini-3-flash-preview';

/**
 * Enhanced retry logic with exponential backoff.
 * For 429 errors, we use a much larger initial delay to allow quota to reset.
 */
async function retryWithBackoff<T>(fn: () => Promise<T>, retries = 6, initialDelay = 5000): Promise<T> {
  let delay = initialDelay;
  for (let i = 0; i < retries; i++) {
    try {
      return await fn();
    } catch (error: any) {
      const errorMsg = error.message || "";
      const isQuotaExceeded = errorMsg.includes("429") || error.status === 429 || errorMsg.includes("RESOURCE_EXHAUSTED") || errorMsg.includes("quota");
      const isRetryable = isQuotaExceeded || (error.status >= 500 && error.status < 600);

      if (i < retries - 1 && isRetryable) {
        // If it's a quota error, wait even longer
        const waitTime = isQuotaExceeded ? delay * (i + 1.5) : delay;
        console.warn(`[Gemini API] Quota reached or server error. Attempt ${i + 1}/${retries}. Retrying in ${Math.round(waitTime/1000)}s...`);
        await new Promise(resolve => setTimeout(resolve, waitTime));
        delay *= 2.5; // Aggressive backoff for quota issues
        continue;
      }
      throw error;
    }
  }
  return fn();
}

export async function analyzeQuestionImage(base64Image: string): Promise<any> {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  const prompt = `
    Analyze this exam question image and provide a TRILINGUAL output (Portuguese, English, Spanish).
    1. Extract question text and translate it to all 3 languages.
    2. Extract all options (A, B, C, D, E) and translate each one to all 3 languages.
    3. Identify the correct answer letter.
    4. Provide a detailed pedagogical explanation in all 3 languages.

    CRITICAL: Ensure technical terms are translated accurately according to professional exam standards.
  `;

  const languageObjectSchema = {
    type: Type.OBJECT,
    properties: {
      pt: { type: Type.STRING },
      en: { type: Type.STRING },
      es: { type: Type.STRING },
    },
    required: ["pt", "en", "es"]
  };

  const optionsLanguageSchema = {
    type: Type.OBJECT,
    properties: {
      pt: { 
        type: Type.OBJECT, 
        properties: { A: {type: Type.STRING}, B: {type: Type.STRING}, C: {type: Type.STRING}, D: {type: Type.STRING}, E: {type: Type.STRING} }
      },
      en: { 
        type: Type.OBJECT, 
        properties: { A: {type: Type.STRING}, B: {type: Type.STRING}, C: {type: Type.STRING}, D: {type: Type.STRING}, E: {type: Type.STRING} }
      },
      es: { 
        type: Type.OBJECT, 
        properties: { A: {type: Type.STRING}, B: {type: Type.STRING}, C: {type: Type.STRING}, D: {type: Type.STRING}, E: {type: Type.STRING} }
      },
    },
    required: ["pt", "en", "es"]
  };

  return retryWithBackoff(async () => {
    const response = await ai.models.generateContent({
      model: MODEL_NAME,
      contents: {
        parts: [
          {
            inlineData: {
              mimeType: 'image/png',
              data: base64Image.split(',')[1] || base64Image,
            },
          },
          { text: prompt },
        ],
      },
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            question: languageObjectSchema,
            options: optionsLanguageSchema,
            correctAnswer: { type: Type.STRING },
            explanations: languageObjectSchema,
          },
          required: ["question", "options", "correctAnswer", "explanations"]
        }
      }
    });

    try {
      const text = response.text;
      if (!text) throw new Error("Empty response from AI");
      return JSON.parse(text);
    } catch (e) {
      console.error("Parse Error during JSON extraction", e);
      throw new Error("Invalid AI response format");
    }
  });
}

import React, { useState, useRef, useEffect } from 'react';
import { AppStatus, QuestionData, ExamSession, HistoryEntry } from './types';
import { analyzeQuestionImage } from './services/geminiService';
import ExamView from './components/ExamView';

// Reduced to 1 for maximum stability on Free Tier (which often allows only a few RPM)
const MAX_CONCURRENT_REQUESTS = 1;
// Spacing of 5 seconds ensures we stay below 12 RPM (most free tiers allow 15 RPM for Flash)
const REQUEST_SPACING = 5000; 

const CACHE_KEY = 'exam_ai_cache_trilingual_v1';
const HISTORY_KEY = 'exam_history_v1';

const App: React.FC = () => {
  const [status, setStatus] = useState<AppStatus>(AppStatus.SETUP);
  const [session, setSession] = useState<ExamSession | null>(null);
  const [history, setHistory] = useState<HistoryEntry[]>([]);
  const [processedCount, setProcessedCount] = useState(0);
  const [totalToProcess, setTotalToProcess] = useState(0);
  const [currentFilePath, setCurrentFilePath] = useState("");
  const [error, setError] = useState<string | null>(null);
  const [isRateLimited, setIsRateLimited] = useState(false);

  const questionsRef = useRef<QuestionData[]>([]);

  useEffect(() => {
    const savedHistory = localStorage.getItem(HISTORY_KEY);
    if (savedHistory) {
      try { setHistory(JSON.parse(savedHistory)); } catch (e) {}
    }
  }, []);

  const saveToHistory = (finalSession: ExamSession) => {
    const newEntry: HistoryEntry = {
      id: finalSession.id,
      date: new Date().toLocaleString('pt-BR'),
      folderName: finalSession.folderName,
      score: finalSession.score,
      total: finalSession.questions.length,
      accuracy: Math.round((finalSession.score / finalSession.questions.length) * 100)
    };
    const updatedHistory = [newEntry, ...history];
    setHistory(updatedHistory);
    localStorage.setItem(HISTORY_KEY, JSON.stringify(updatedHistory));
  };

  const handleFileUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const files = e.target.files;
    if (!files || files.length === 0) return;

    setStatus(AppStatus.LOADING);
    setError(null);
    setIsRateLimited(false);
    setProcessedCount(0);
    questionsRef.current = [];

    const fileArray = Array.from(files) as (File & { webkitRelativePath?: string })[];
    const validImageFiles = fileArray.filter(file => 
      file.type.startsWith('image/png') || file.type.startsWith('image/jpeg')
    );

    setTotalToProcess(validImageFiles.length);
    if (validImageFiles.length === 0) {
      setError("Nenhuma imagem válida encontrada.");
      setStatus(AppStatus.SETUP);
      return;
    }

    const folderName = validImageFiles[0].webkitRelativePath?.split('/')[0] || "Simulado Trilingue";

    const processBatch = async () => {
      const queue = [...validImageFiles];
      const workers = [];
      const cacheRaw = localStorage.getItem(CACHE_KEY);
      const cache = cacheRaw ? JSON.parse(cacheRaw) : {};

      const worker = async () => {
        while (queue.length > 0) {
          const file = queue.shift();
          if (!file) break;
          const cacheId = `${file.name}_${file.size}`;
          setCurrentFilePath(file.webkitRelativePath || file.name);

          try {
            const reader = new FileReader();
            const base64 = await new Promise<string>((resolve) => {
              reader.onload = () => resolve(reader.result as string);
              reader.readAsDataURL(file);
            });

            let result;
            if (cache[cacheId]) {
              result = cache[cacheId];
              // Small delay for UI smoothness even with cache
              await new Promise(r => setTimeout(r, 200));
            } else {
              result = await analyzeQuestionImage(base64);
              cache[cacheId] = result;
              localStorage.setItem(CACHE_KEY, JSON.stringify(cache));
              // Mandatory spacing to stay within RPM limits
              await new Promise(r => setTimeout(r, REQUEST_SPACING));
            }

            const newQuestion: QuestionData = {
              id: `q-${Math.random().toString(36).substr(2, 9)}`,
              image: base64,
              texts: {
                question: result.question,
                options: result.options
              },
              correctAnswer: result.correctAnswer,
              explanations: result.explanations
            };

            questionsRef.current.push(newQuestion);
            setSession(prev => prev ? { ...prev, questions: [...questionsRef.current] } : null);
          } catch (err: any) {
            console.error(`Error processing ${file.name}:`, err);
            const msg = err.message || "";
            if (msg.includes("429") || msg.includes("RESOURCE_EXHAUSTED")) {
              setIsRateLimited(true);
            }
          } finally {
            setProcessedCount(prev => prev + 1);
          }
        }
      };

      for (let i = 0; i < Math.min(MAX_CONCURRENT_REQUESTS, validImageFiles.length); i++) {
        workers.push(worker());
      }
      await Promise.all(workers);
      setSession(prev => prev ? { ...prev, isStillLoading: false } : null);
      if (status === AppStatus.LOADING && questionsRef.current.length > 0) startExam(folderName);
    };
    processBatch();
  };

  const startExam = (folderName: string) => {
    setSession({
      id: Date.now().toString(),
      folderName,
      questions: [...questionsRef.current],
      currentIndex: 0,
      score: 0,
      answers: {},
      isFinished: false,
      isStillLoading: processedCount < totalToProcess
    });
    setStatus(AppStatus.EXAM);
  };

  const handleAnswer = (selected: string) => {
    if (!session) return;
    const isCorrect = selected === session.questions[session.currentIndex].correctAnswer;
    setSession(prev => prev ? ({
      ...prev,
      score: isCorrect ? prev.score + 1 : prev.score,
      answers: { ...prev.answers, [prev.questions[prev.currentIndex].id]: selected }
    }) : null);
  };

  const handleNext = () => {
    if (!session) return;
    if (session.currentIndex + 1 >= session.questions.length) {
      if (session.isStillLoading) return;
      saveToHistory(session);
      setStatus(AppStatus.RESULT);
    } else {
      setSession(prev => prev ? ({ ...prev, currentIndex: prev.currentIndex + 1 }) : null);
    }
  };

