                    <p className="text-slate-400 font-medium italic">Nenhum simulado salvo no disco ainda. Carregue uma pasta para começar.</p>
                  </div>
                ) : (
                  <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                    {savedExams.map(exam => (
                      <div 
                        key={exam.id} 
                        onClick={() => loadSavedExam(exam)}
                        className="group bg-white p-6 rounded-3xl border border-slate-100 shadow-sm hover:shadow-xl hover:border-indigo-200 transition-all cursor-pointer relative overflow-hidden"
                      >
                        <div className="absolute top-0 left-0 w-1.5 h-full bg-indigo-500 transform -translate-x-full group-hover:translate-x-0 transition-transform"></div>
                        <div className="flex justify-between items-start mb-4">
                           <div className="w-10 h-10 bg-slate-50 rounded-xl flex items-center justify-center text-slate-400 group-hover:text-indigo-600 group-hover:bg-indigo-50 transition-colors">
                              <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M5 8h14M5 8a2 2 0 110-4h14a2 2 0 110 4M5 8v10a2 2 0 002 2h10a2 2 0 002-2V8m-9 4h4" /></svg>
                           </div>
                           <button 
                             onClick={(e) => handleDeleteSaved(e, exam.id)}
                             className="text-slate-300 hover:text-rose-500 p-2 transition-colors"
                           >
                             <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" /></svg>
                           </button>
                        </div>
                        <h4 className="font-bold text-slate-800 line-clamp-1 group-hover:text-indigo-600 transition-colors">{exam.folderName}</h4>
                        <div className="flex items-center gap-3 mt-4 text-[10px] font-black text-slate-400 uppercase tracking-tighter">
                          <span>{exam.questions.length} Questões</span>
                          <div className="w-1 h-1 bg-slate-200 rounded-full"></div>
                          <span className="text-indigo-500">Offline Ready</span>
                        </div>
                      </div>
                    ))}
                  </div>
                )}
              </div>

            </div>
          </div>
        )}

        {status === AppStatus.LOADING && (
          <div className="py-32 text-center max-w-xl mx-auto">
             <div className="relative w-40 h-40 mx-auto mb-12">
               <div className="absolute inset-0 border-[12px] border-slate-100 rounded-full"></div>
               <div 
                 className="absolute inset-0 border-[12px] border-indigo-600 rounded-full border-t-transparent animate-spin"
                 style={{ animationDuration: '2s' }}
               ></div>
               <div className="absolute inset-0 flex flex-col items-center justify-center">
                 <span className="text-3xl font-black text-slate-900">{processedCount}/{totalToProcess}</span>
                 <span className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">Lendo Disco</span>
               </div>
            </div>

            <h3 className="text-3xl font-black mb-3 text-slate-900">Processando e Salvando...</h3>
            <p className="text-slate-500 font-medium mb-12 italic">"{currentFilePath}"</p>

            <div className="flex flex-col gap-3">
              <div className="flex justify-between text-[10px] font-black text-slate-400 uppercase px-2">
                 <span>Status do Processamento</span>
                 <span>{Math.round((processedCount/totalToProcess)*100)}%</span>
              </div>
              <div className="w-full bg-slate-100 h-3 rounded-full overflow-hidden">
                 <div className="bg-indigo-600 h-full transition-all duration-500" style={{ width: `${(processedCount/totalToProcess)*100}%` }}></div>
              </div>
            </div>
          </div>
        )}

        {status === AppStatus.EXAM && session && (
          <ExamView 
            question={session.questions[session.currentIndex]}
            currentIndex={session.currentIndex}
            totalQuestions={session.questions.length}
            onAnswer={(s) => {
              const correct = s === session.questions[session.currentIndex].correctAnswer;
              setSession(prev => prev ? ({ ...prev, score: correct ? prev.score + 1 : prev.score, answers: { ...prev.answers, [prev.questions[prev.currentIndex].id]: s } }) : null);
            }}
            onNext={() => {
              if (session.currentIndex + 1 >= session.questions.length) {
                saveToHistory(session);
                setStatus(AppStatus.RESULT);
              } else {
                setSession(prev => prev ? ({ ...prev, currentIndex: prev.currentIndex + 1 }) : null);
              }
            }}
          />
        )}

        {status === AppStatus.RESULT && session && (
          <div className="py-20 max-w-2xl mx-auto text-center">
            <div className="bg-white p-12 rounded-[3rem] shadow-2xl border border-slate-100">
              <div className="text-6xl mb-8">🚀</div>
              <h2 className="text-4xl font-black mb-4">Análise Concluída</h2>
              <div className="grid grid-cols-2 gap-6 my-12">
                <div className="p-8 bg-slate-50 rounded-[2rem] border border-slate-100">
                  <div className="text-5xl font-black text-slate-900">{session.score}</div>
                  <div className="text-[10px] font-bold text-slate-400 uppercase tracking-widest mt-2">Acertos</div>
                </div>
                <div className="p-8 bg-slate-50 rounded-[2rem] border border-slate-100">
                  <div className="text-5xl font-black text-slate-900">{Math.round((session.score / session.questions.length) * 100)}%</div>
                  <div className="text-[10px] font-bold text-slate-400 uppercase tracking-widest mt-2">Score Final</div>
                </div>
              </div>
              <button onClick={reset} className="w-full bg-slate-900 text-white font-black py-5 rounded-2xl shadow-lg text-lg hover:bg-black transition-colors">
                Voltar para Biblioteca
              </button>
            </div>
          </div>
        )}
      </main>

      <footer className="py-12 text-center border-t border-slate-200 mt-20">
         <p className="text-[10px] font-bold text-slate-400 uppercase tracking-[0.3em]">SmartStudy On-Premise Engine • Laptop Edition</p>
      </footer>
    </div>
  );
};

export default App;

